import{_ as t,c as i,a1 as n,o as a}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Sniffing","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/7-sniffing/0-Introduction.md","filePath":"categories/ethical-hacking-labs/7-sniffing/0-Introduction.md"}'),s={name:"categories/ethical-hacking-labs/7-sniffing/0-Introduction.md"};function o(r,e,l,c,f,h){return a(),i("div",null,e[0]||(e[0]=[n('<h1 id="sniffing" tabindex="-1">Sniffing <a class="header-anchor" href="#sniffing" aria-label="Permalink to &quot;Sniffing&quot;">​</a></h1><p>Sniffing is the process of monitoring and capturing all the packets passing through a given network using sniffing tools. It is a form of “tapping phone wires” and get to know about the conversation. It is also called wiretapping applied to the computer networks.</p><p align="center"><img width="68%" src="https://www.bettercap.org/legacy/assets/img/mitm.jpg"></p><p>There is so much possibility that if a set of enterprise switch ports is open, then one of their employees can sniff the whole traffic of the network. Anyone in the same physical location can plug into the network using Ethernet cable or connect wirelessly to that network and sniff the total traffic.</p><h3 id="what-can-be-sniffed" tabindex="-1">What can be sniffed? <a class="header-anchor" href="#what-can-be-sniffed" aria-label="Permalink to &quot;What can be sniffed?&quot;">​</a></h3><ul><li>Email traffic</li><li>FTP passwords</li><li>Web traffics</li><li>Telnet passwords</li><li>Router configuration</li><li>Chat sessions</li><li>DNS traffic</li></ul><h2 id="types-of-sniffing" tabindex="-1">Types of Sniffing <a class="header-anchor" href="#types-of-sniffing" aria-label="Permalink to &quot;Types of Sniffing&quot;">​</a></h2><p><em>Sniffing can be either <strong>Active</strong> or <strong>Passive</strong>.</em></p><h3 id="in-passive-sniffing" tabindex="-1">In passive sniffing, <a class="header-anchor" href="#in-passive-sniffing" aria-label="Permalink to &quot;In passive sniffing,&quot;">​</a></h3><p>the traffic is locked but it is not altered in any way. Passive sniffing allows listening only. It works with Hub devices. On a hub device, the traffic is sent to all the ports. In a network that uses hubs to connect systems, all hosts on the network can see the traffic. Therefore, an attacker can easily capture traffic going through.</p><h3 id="in-active-sniffing" tabindex="-1">In active sniffing, <a class="header-anchor" href="#in-active-sniffing" aria-label="Permalink to &quot;In active sniffing,&quot;">​</a></h3><p>the traffic is not only locked and monitored, but it may also be altered in some way as determined by the attack. Active sniffing is used to sniff a switch-based network. It involves injecting address resolution packets (ARP) into a target network to flood on the switch content addressable memory (CAM) table. CAM keeps track of which host is connected to which port.</p><p>Some Active Sniffing techniques:</p><ul><li>MAC Flooding</li><li>DHCP Attacks</li><li>DNS Poisoning</li><li>Spoofing Attacks</li><li>ARP Poisoning</li></ul><h2 id="protocols-which-are-affected" tabindex="-1">Protocols which are affected <a class="header-anchor" href="#protocols-which-are-affected" aria-label="Permalink to &quot;Protocols which are affected&quot;">​</a></h2><p>Protocols such as the tried and true TCP/IP were never designed with security in mind and therefore do not offer much resistance to potential intruders. Several rules lend themselves to easy sniffing.</p><ul><li><p><strong>HTTP</strong> − It is used to send information in the clear text without any encryption and thus a real target.</p></li><li><p><strong>SMTP</strong> <em>(Simple Mail Transfer Protocol)</em> − SMTP is basically utilized in the transfer of emails. This protocol is efficient, but it does not include any protection against sniffing.</p></li><li><p><strong>NNTP</strong> <em>(Network News Transfer Protocol)</em>− It is used for all types of communications, but its main drawback is that data and even passwords are sent over the network as clear text.</p></li><li><p><strong>POP</strong> <em>(Post Office Protocol)</em> − POP is strictly used to receive emails from the servers. This protocol does not include protection against sniffing because it can be trapped.</p></li><li><p><strong>FTP</strong> <em>(File Transfer Protocol)</em> − FTP is used to send and receive files, but it does not offer any security features. All the data is sent as clear text that can be easily sniffed.</p></li><li><p><strong>IMAP</strong> <em>(Internet Message Access Protocol)</em> − IMAP is same as SMTP in its functions, but it is highly vulnerable to sniffing.</p></li><li><p><strong>Telnet</strong> − Telnet sends everything (usernames, passwords, keystrokes) over the network as clear text and hence, it can be easily sniffed.</p></li></ul><p>_Source: <a href="https://www.tutorialspoint.com/ethical_hacking/ethical_hacking_sniffing.htm_" target="_blank" rel="noreferrer">https://www.tutorialspoint.com/ethical_hacking/ethical_hacking_sniffing.htm_</a></p>',18)]))}const g=t(s,[["render",o]]);export{p as __pageData,g as default};
